class Solution:
    def heapify(self, nums: list[int], n: int, i: int) -> None:
        if i >= n or i * 2 + 1 >= n:
            return
        if nums[i] > nums[i * 2 + 1]:
            swap(nums[i], nums[i * 2 + 1])
        elif nums[i] > nums[i * 2 + 2]:
            swap(nums[i], nums[i * 2 + 2])
        if i * 2 + 1 < n:
            self.heapify(nums, n, i * 2 + 1)
        if i * 2 + 2 < n:
            self.heapify(nums, n, i * 2 + 2)


def swap(a, b):
    a, b = b, a
    return a, b

def main():
    nums = [int(x) for x in input().split()]
    n = int(input())
    heapify_idx = int(input())
    nums = Solution().heapify(nums, n, heapify_idx)
    print(' '.join(map(str, nums)))

if __name__ == '__main__':
    main()

