class Solution {
public:
    void heapify(vector<int>& nums, int n, int i) {
        if (i >= n || i * 2 + 1 >= n) return;
        int largest = i;
        if (nums[i] < nums[i * 2 + 1]) largest = i * 2 + 1;
        if (nums[largest] < nums[i * 2 + 2]) largest = i * 2 + 2;
        if (largest == i) return;
        swap(nums[i], nums[largest]);
        heapify(nums, n, largest);
    }
};

